# Shape abstractions and interfaces - base module

interface IDrawable:
    def draw(self) -> str: ...

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

@abstract
class Shape:
    name: str
    shape_type: ShapeType

    def __init__(self, name: str, shape_type: ShapeType):
        self.name = name
        self.shape_type = shape_type

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

