# Concrete shape implementations and geometry types

from shapes import Shape, ShapeType, IDrawable

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return pow(dx * dx + dy * dy, 0.5)

class Circle(Shape, IDrawable):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__("Circle", ShapeType.CIRCLE)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing circle at ({self.center.x}, {self.center.y})"

class Rectangle(Shape, IDrawable):
    top_left: Point
    width: float
    height: float

    def __init__(self, top_left: Point, width: float, height: float):
        super().__init__("Rectangle", ShapeType.RECTANGLE)
        self.top_left = top_left
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Drawing rectangle at ({self.top_left.x}, {self.top_left.y})"

