# Utility functions and static helpers for shape operations

from shapes import Shape, IDrawable
from geometry import Point, Circle

class ShapeStats:
    @staticmethod
    def total_area(shapes: list[Shape]) -> float:
        total: float = 0.0
        for shape in shapes:
            total += shape.area()
        return total

    @staticmethod
    def count_drawable(shapes: list[Shape]) -> int:
        count: int = 0
        for shape in shapes:
            if isinstance(shape, IDrawable):
                count += 1
        return count

def create_circle_at_origin(radius: float) -> Circle:
    origin: Point = Point(0.0, 0.0)
    return Circle(origin, radius)

def format_shape_info(shape: Shape) -> str:
        # Using type narrowing with shapeType to show polymorphism in action
        if isinstance(shape, Circle):
                return f"Circle[r={shape.radius}]: area={shape.area()}, perimeter={shape.perimeter()}"
        return f"{shape.name}: area={shape.area()}, perimeter={shape.perimeter()}"
